mapper.update:
UPDATE TB_BOX_IVT_BNNR_INFO_M
SET
    BNNR_PHRS_CON      = #{params.bnnrPhrsCon}
    , BNNR_IMG_FILE_ID = #{params.bnnrImgFileId}
    , BTN_PHRS_CON     = #{params.btnPhrsCon}
    , BNNR_LNKN_URL    = #{params.bnnrLnknUrl}
    , EXPU_YN          = #{params.expuYn}
    , AMNN_USER_ID     = #{params.amnnUserId}
    , AMNN_TS          = CURRENT_TIMESTAMP
WHERE 1=1
AND BNNR_COM_CD_ID = #{bnnrComCdId}
AND BNNR_SQN = #{bnnrSqn}

mapper.select:
SELECT BNNR_COM_CD_ID , BNNR_SQN , BNNR_PHRS_CON , BNNR_IMG_FILE_ID AS IMG_FILE_ID , BNNR_IMG_FILE_ID AS FILE_ID , BTN_PHRS_CON , BNNR_LNKN_URL , EXPU_YN , RGSN_USER_ID , RGSN_TS , AMNN_USER_ID , AMNN_TS FROM TB_BOX_IVT_BNNR_INFO_M WHERE 1=1 AND BNNR_COM_CD_ID = #{bnnrComCdId}
AND EXPU_YN = 'Y'
ORDER BY BNNR_SQN ASC
